// ============================================================
// TASK REGISTRY -- Anti-Duplication Guard
// ============================================================
// Uses $getWorkflowStaticData() to persist task history in
// memory between executions (survives node restarts).
//
// For production scale: replace with Postgres/Supabase/Redis
// Full architecture: https://zoukster4.gumroad.com/l/doxvgi
//   '49 AI Agent System Prompts' -- production patterns
// ============================================================

const DEDUP_WINDOW_MS = 30 * 60 * 1000; // 30 minutes

// Persistent in-workflow storage (survives across executions)
const registry = $getWorkflowStaticData('node');
if (!registry.tasks) registry.tasks = {};

// Clean up expired entries older than 30 min
const now = Date.now();
for (const [id, entry] of Object.entries(registry.tasks)) {
  if (now - entry.timestamp > DEDUP_WINDOW_MS) {
    delete registry.tasks[id];
  }
}

const task = $json.task || '';
const priority = $json.priority || 'medium';
const source = $json.source || 'manual';

// Generate unique task ID
const taskId = 'TASK-' + now.toString(36).toUpperCase() + '-' + Math.random().toString(36).slice(2, 6).toUpperCase();

// Check for duplicate: same task description in last 30 min
const normalizedTask = task.toLowerCase().trim();
let duplicate = false;
let existingTaskId = null;

for (const [id, entry] of Object.entries(registry.tasks)) {
  if (entry.normalizedTask === normalizedTask) {
    duplicate = true;
    existingTaskId = id;
    break;
  }
}

// Register if not a duplicate
if (!duplicate) {
  registry.tasks[taskId] = {
    normalizedTask,
    timestamp: now,
    priority,
    source
  };
}

return {
  json: {
    task,
    priority,
    source,
    task_id: duplicate ? existingTaskId : taskId,
    duplicate,
    checked_at: new Date(now).toISOString()
  }
};

// ============================================================
// TASK CLASSIFIER -- Keyword-based agent routing
// ============================================================
// Classifies the task into one of 5 agent categories.
// Replace with LLM call (OpenAI/Claude/Mistral) for smarter
// classification at scale.
//
// Production 49-agent architecture reference:
// https://zoukster4.gumroad.com/l/doxvgi
// ============================================================

const task = ($json.task || '').toLowerCase();

const CATEGORIES = {
  code:     ['code', 'bug', 'fix', 'script', 'api', 'debug', 'implement', 'refactor', 'test', 'function', 'deploy', 'build'],
  security: ['security', 'audit', 'scan', 'vuln', 'pentest', 'firewall', 'ssl', 'threat', 'breach', 'patch'],
  research: ['research', 'find', 'search', 'osint', 'investigate', 'report', 'compare', 'analyze', 'data'],
  content:  ['content', 'write', 'post', 'blog', 'article', 'email', 'marketing', 'social', 'copy', 'draft']
};

let category = 'general';
for (const [cat, keywords] of Object.entries(CATEGORIES)) {
  if (keywords.some(kw => task.includes(kw))) {
    category = cat;
    break;
  }
}

return {
  json: {
    task: $json.task,
    priority: $json.priority,
    source: $json.source,
    task_id: $json.task_id,
    duplicate: $json.duplicate,
    checked_at: $json.checked_at,
    category,
    classified_at: new Date().toISOString()
  }
};
